fileprivate struct UniffiCallbackInterfaceProjectionSubscriber {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // Store the vtable directly.
    static let vtable: UniffiVTableCallbackInterfaceProjectionSubscriber = UniffiVTableCallbackInterfaceProjectionSubscriber(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterTypeProjectionSubscriber.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface ProjectionSubscriber: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterTypeProjectionSubscriber.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface ProjectionSubscriber: handle missing in uniffiClone")
            }
        },
        receive: { (
            uniffiHandle: UInt64,
            projection: RustBuffer,
            uniffiOutReturn: UnsafeMutableRawPointer,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> () in
                guard let uniffiObj = try? FfiConverterTypeProjectionSubscriber.handleMap.get(handle: uniffiHandle) else {
