    // for the process lifetime (not just for the init function call).
    //
    // `nonisolated(unsafe)` is needed under Swift 6 strict concurrency.
    // This is safe because the pointee is initialized once during static init
    // and never mutated by either side of the FFI.  Its fields are C function pointers.
    nonisolated(unsafe) static let vtablePtr: UnsafePointer<UniffiVTableCallbackInterfaceProjectionSubscriber> = {
        let ptr = UnsafeMutablePointer<UniffiVTableCallbackInterfaceProjectionSubscriber>.allocate(capacity: 1)
